1	export type Customer = {
2	  yearsWithMHPCO: number;
3	};
4	
5	export type Item = {
6	  type: string;
7	  cursed?: boolean;
8	};
9	
10	export type QuoteStep = {
11	  op: "quote";
12	  items: Item[];
13	};
14	
15	export type Step = QuoteStep;
16	
17	export type Scenario = {
18	  customer: Customer;
19	  steps: Step[];
20	};
21	
22	export type QuoteResult = {
23	  premium: number;
24	};
25	
26	export type Result = QuoteResult;
27	
28	const PROCESSING_FEE = 5;
29	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
30	const CURSE_SURCHARGE_RATE = 0.5;
31	
32	const BASE_PREMIUMS: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const COMPONENT_BLOCK_SIZE = 3;
42	const COMPONENT_BLOCK_PREMIUM = 60;
43	
44	const countByType = (items: Item[]): Map<string, number> => {
45	  const counts = new Map<string, number>();
46	  for (const item of items) {
47	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
48	  }
49	  return counts;
50	};
51	
52	const groupBasePremium = (type: string, count: number): number =>
53	  count === COMPONENT_BLOCK_SIZE
54	    ? COMPONENT_BLOCK_PREMIUM
55	    : count * BASE_PREMIUMS[type];
56	
57	const computeBasePremium = (items: Item[]): number =>
58	  [...countByType(items)].reduce(
59	    (total, [type, count]) => total + groupBasePremium(type, count),
60	    0,
61	  );
62	
63	const itemCurseSurcharge = (item: Item): number =>
64	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
65	
66	const computeCurseSurcharge = (items: Item[]): number =>
67	  items.reduce((total, item) => total + itemCurseSurcharge(item), 0);
68	
69	const quotePremium = (items: Item[]): number => {
70	  const basePremium = computeBasePremium(items);
71	  const curseSurcharge = computeCurseSurcharge(items);
72	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
73	  const exactPremium =
74	    basePremium + curseSurcharge + firstInsuranceSurcharge + PROCESSING_FEE;
75	  return Math.ceil(exactPremium);
76	};
77	
78	export const processScenario = (scenario: Scenario): { results: Result[] } => {
79	  return { results: [{ premium: quotePremium(scenario.steps[0].items) }] };
80	};
