const quotePremium = (customer: Customer, items: Item[]): number => {
  const basePremium = computeBasePremium(items);
  const curseSurcharge = computeCurseSurcharge(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  const loyaltyDiscount =
    customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
      ? basePremium * LOYALTY_DISCOUNT_RATE
      : 0;
  const exactPremium =
    basePremium +
    curseSurcharge +
    firstInsuranceSurcharge -
    loyaltyDiscount +
    PROCESSING_FEE;
  return Math.ceil(exactPremium);
};

export const processScenario = (scenario: Scenario): { results: Result[] } => {
  return {
    results: [
      { premium: quotePremium(scenario.customer, scenario.steps[0].items) },
    ],
  };
};
